/**
 * third-brain Pi extension — Penny's long-term memory
 *
 * Hooks into pi lifecycle to:
 * - Inject brain context at session start
 * - Collect messages for consolidation
 * - Provide memory tools (remember, recall, forget, stats)
 *
 * Logging: uses status bar (setStatus), notifications (notify),
 * and console.error (debug log) for visibility at every lifecycle point.
 */

import type { ExtensionAPI, AgentToolResult } from "@mariozechner/pi-coding-agent";
import { Type } from "@sinclair/typebox";
import { join } from "node:path";
import { homedir } from "node:os";
import { execFileSync } from "node:child_process";

type ToolResult = AgentToolResult<unknown>;
function ok(text: string): ToolResult {
  return { content: [{ type: "text", text }], details: {} };
}

const HOME = homedir();
const THIRD_BRAIN_DIR = join(HOME, "repos", "nikbrunner", "third-brain");
const SCRIPTS_DIR = join(THIRD_BRAIN_DIR, "scripts");
const TSX = join(THIRD_BRAIN_DIR, "node_modules", ".bin", "tsx");

interface RunResult {
  stdout: string;
  stderr: string;
  ok: boolean;
}

function runScript(script: string, ...args: string[]): RunResult {
  try {
    const result = execFileSync(TSX, [join(SCRIPTS_DIR, script), ...args], {
      encoding: "utf8",
      timeout: 15_000,
      maxBuffer: 1024 * 1024,
      cwd: THIRD_BRAIN_DIR,
      stdio: ["pipe", "pipe", "pipe"],
    });
    // For execFileSync with stdio pipe, result is the stdout string directly
    return { stdout: (result || "").trim(), stderr: "", ok: true };
  } catch (err: unknown) {
    const e = err as { stdout?: string; stderr?: string; message?: string; code?: string };
    if (e.code === "ETIMEDOUT") {
      return { stdout: "", stderr: `${script}: timed out`, ok: false };
    }
    return { stdout: e.stdout || "", stderr: e.stderr || e.message || "Unknown error", ok: false };
  }
}

function runScriptWithInput(script: string, input: string, ...args: string[]): RunResult {
  try {
    const result = execFileSync(TSX, [join(SCRIPTS_DIR, script), ...args], {
      encoding: "utf8",
      timeout: 45_000,
      maxBuffer: 1024 * 1024,
      cwd: THIRD_BRAIN_DIR,
      input,
      stdio: ["pipe", "pipe", "pipe"],
    });
    // For execFileSync with stdio pipe, result is the stdout string directly
    return { stdout: (result || "").trim(), stderr: "", ok: true };
  } catch (err: unknown) {
    const e = err as { stdout?: string; stderr?: string; message?: string; code?: string };
    if (e.code === "ETIMEDOUT") {
      return { stdout: "", stderr: `${script}: timed out`, ok: false };
    }
    return { stdout: e.stdout || "", stderr: e.stderr || e.message || "Unknown error", ok: false };
  }
}

/** Parse "Index: 75 files" → 75 */
function parseFileCount(stdout: string): number {
  const m = stdout.match(/Index:\s+(\d+)\s+files/);
  return m ? parseInt(m[1], 10) : 0;
}

/** Parse "Extracted X memories" → X */
function parseExtractedCount(stdout: string): number {
  const m = stdout.match(/Extracted\s+(\d+)\s+memor/);
  return m ? parseInt(m[1], 10) : 0;
}

/** Count result entries from recall output */
function countRecallResults(stdout: string): number {
  return (stdout.match(/^\[/gm) || []).length;
}

function extractText(content: unknown): string {
  if (typeof content === "string") return content;
  if (Array.isArray(content)) {
    return content
      .filter((c: any) => c.type === "text" && typeof c.text === "string")
      .map((c: any) => c.text)
      .join("\n");
  }
  return "";
}

export default function (pi: ExtensionAPI) {
  let pendingUserMessages: string[] = [];
  let pendingAssistantMessages: string[] = [];
  let sessionMsgCount = 0;

  // ─── Lifecycle ──────────────────────────────────────────────────────

  pi.on("session_start", async (_event, ctx) => {
    const startTime = Date.now();

    const stats = runScript("sync-index.ts");
    const fileCount = parseFileCount(stats.stdout);

    if (stats.ok && fileCount > 0) {
      const elapsed = Date.now() - startTime;
      console.error(`[third-brain] ✅ Loaded: ${fileCount} files indexed (${elapsed}ms)`);
      ctx.ui.setStatus("third-brain", `🧠 ${fileCount} memories`);
      setTimeout(() => {
        try { ctx.ui.setStatus("third-brain", ""); } catch { /* ctx stale */ }
      }, 5000);
    } else if (!stats.ok) {
      console.error(`[third-brain] ⚠️ Index unavailable: ${stats.stderr}`);
      ctx.ui.setStatus("third-brain", `🧠 ⚠️ offline`);
    } else {
      console.error(`[third-brain] ⚠️ Empty (0 files). Run bootstrap?`);
      ctx.ui.setStatus("third-brain", `🧠 empty`);
    }
  });

  pi.on("before_agent_start", async (event, ctx) => {
    const prompt = event.prompt;
    ctx.ui.setStatus("third-brain", "🔍 Searching memories...");

    try {
      const result = execFileSync(TSX, [
        join(SCRIPTS_DIR, "recall.ts"),
        prompt,
        "--limit", "5",
      ], {
        encoding: "utf8",
        timeout: 10_000,
        maxBuffer: 256 * 1024,
        cwd: THIRD_BRAIN_DIR,
      });

      const stdout = result.stdout?.trim() || "";
      const found = countRecallResults(stdout);

      if (found > 0) {
        console.error(`[third-brain] Injected ${found} relevant memories for: "${prompt.slice(0, 80)}..."`);
        ctx.ui.setStatus("third-brain", `🧠 ${found} memories found`);
        setTimeout(() => {
          try { ctx.ui.setStatus("third-brain", ""); } catch { /* stale */ }
        }, 3000);

        return {
          systemPrompt: `${event.systemPrompt}\n\n<memory>\nRelevant memories from Penny's brain:\n${stdout}\n</memory>`,
        };
      } else {
        ctx.ui.setStatus("third-brain", "");
      }
    } catch {
      console.error(`[third-brain] ⚠️ Search failed for prompt`);
      ctx.ui.setStatus("third-brain", "");
    }
  });

  pi.on("agent_end", async (event, _ctx) => {
    sessionMsgCount++;
    for (const msg of event.messages) {
      if (msg.role === "user" && "content" in msg) {
        const text = extractText(msg.content);
        if (text) {
          pendingUserMessages.push(text);
          if (pendingUserMessages.length > 60) pendingUserMessages.shift();
        }
      } else if (msg.role === "assistant" && "content" in msg) {
        const text = extractText(msg.content);
        if (text) {
          pendingAssistantMessages.push(text);
          if (pendingAssistantMessages.length > 60) pendingAssistantMessages.shift();
        }
      }
    }
  });

  pi.on("session_before_switch", async (_event, ctx) => {
    if (pendingUserMessages.length >= 3) {
      console.error(`[third-brain] Consolidating ${pendingUserMessages.length} turns...`);
      ctx.ui.setStatus("third-brain", "🧠 Consolidating...");

      try {
        const messages = pendingUserMessages.map((m, i) => ({
          role: "user",
          content: m,
          reply: pendingAssistantMessages[i] || "",
        }));
        const result = runScriptWithInput("consolidate.ts", JSON.stringify(messages));
        const extracted = parseExtractedCount(result.stdout);

        if (result.ok && extracted > 0) {
          console.error(`[third-brain] ✅ Consolidated: ${extracted} new memories`);
          ctx.ui.setStatus("third-brain", `🧠 +${extracted} memories saved`);
        } else if (result.ok) {
          console.error(`[third-brain] Consolidation ran — nothing new`);
          ctx.ui.setStatus("third-brain", "");
        } else {
          console.error(`[third-brain] ⚠️ Consolidation failed: ${result.stderr}`);
          ctx.ui.setStatus("third-brain", "");
        }
      } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : String(err);
        console.error(`[third-brain] ⚠️ Consolidation error: ${msg}`);
        ctx.ui.setStatus("third-brain", "");
      }

      setTimeout(() => {
        try { ctx.ui.setStatus("third-brain", ""); } catch { /* stale */ }
      }, 5000);

      pendingUserMessages = [];
      pendingAssistantMessages = [];
    }
  });

  pi.on("session_shutdown", async () => {
    if (pendingUserMessages.length >= 3) {
      console.error(`[third-brain] Shutdown: consolidating ${pendingUserMessages.length} turns...`);
      try {
        const messages = pendingUserMessages.map((m, i) => ({
          role: "user",
          content: m,
          reply: pendingAssistantMessages[i] || "",
        }));
        const result = runScriptWithInput("consolidate.ts", JSON.stringify(messages));
        const extracted = parseExtractedCount(result.stdout);
        if (result.ok && extracted > 0) {
          console.error(`[third-brain] ✅ Shutdown consolidated: ${extracted} memories`);
        }
      } catch (err: unknown) {
        const msg = err instanceof Error ? err.message : String(err);
        console.error(`[third-brain] ⚠️ Shutdown consolidation: ${msg}`);
      }
    }
  });

  // ─── Tools ──────────────────────────────────────────────────────────

  pi.registerTool({
    name: "brain_remember",
    label: "Brain Remember",
    description: "Write a memory to Penny's third-brain. Use for decisions, corrections, personal facts, or project insights worth keeping across sessions.",
    parameters: Type.Object({
      content: Type.String({ description: "The fact, decision, or observation to remember (one sentence)" }),
      type: Type.Optional(Type.String({ description: "Memory type: person, projects, patterns, sessions, self, or daily (default)" })),
      tags: Type.Optional(Type.String({ description: "Comma-separated tags for categorization" })),
    }) as any,
    async execute(_id, params, _signal, _update, _ctx) {
      const type = params.type || "daily";
      const tags = params.tags || "";

      const result = runScript("remember.ts",
        "--content", params.content,
        "--type", type,
        "--tags", tags,
      );

      if (result.ok) {
        console.error(`[third-brain] ✅ Remembered [${type}]: ${params.content.slice(0, 80)}`);
        return ok(result.stdout || `🧠 Remembered [${type}]: ${params.content}`);
      } else {
        console.error(`[third-brain] ⚠️ remember failed: ${result.stderr}`);
        return ok(`⚠️ Failed to remember: ${result.stderr}`);
      }
    },
  });

  pi.registerTool({
    name: "brain_recall",
    label: "Brain Recall",
    description: "Search Penny's third-brain for relevant memories, facts, or context.",
    parameters: Type.Object({
      query: Type.String({ description: "Search query" }),
      type: Type.Optional(Type.String({ description: "Filter by type: person, projects, patterns, sessions, self" })),
      limit: Type.Optional(Type.Number({ description: "Max results (default 5)" })),
    }) as any,
    async execute(_id, params, _signal, _update, _ctx) {
      const limit = params.limit || 5;
      const args = [params.query, "--limit", String(limit)];
      if (params.type) args.push("--type", params.type);

      const result = runScript("recall.ts", ...args);
      const found = countRecallResults(result.stdout);

      console.error(`[third-brain] Recall "${params.query.slice(0, 60)}" → ${found} results`);

      if (result.ok && found > 0) {
        return ok(`🧠 Found ${found} memories:\n\n${result.stdout}`);
      } else if (result.ok) {
        return ok("🧠 No matching memories found.");
      } else {
        return ok(`⚠️ Recall failed: ${result.stderr}`);
      }
    },
  });

  pi.registerTool({
    name: "brain_forget",
    label: "Brain Forget",
    description: "Remove a memory from Penny's third-brain.",
    parameters: Type.Object({
      file: Type.String({ description: "Brain file path (e.g., person/nik.md)" }),
      match: Type.String({ description: "Text to match for removal" }),
      section: Type.Optional(Type.String({ description: "Section heading to search within" })),
    }) as any,
    async execute(_id, params, _signal, _update, _ctx) {
      const args = ["--file", params.file, "--match", params.match];
      if (params.section) args.push("--section", params.section);

      const result = runScript("forget.ts", ...args);

      if (result.ok) {
        console.error(`[third-brain] 🗑️ Forgotten from ${params.file}: "${params.match.slice(0, 60)}"`);
        return ok(result.stdout || `🗑️ Removed "${params.match}" from ${params.file}`);
      } else {
        console.error(`[third-brain] ⚠️ forget failed: ${result.stderr}`);
        return ok(`⚠️ Forget failed: ${result.stderr}`);
      }
    },
  });

  pi.registerTool({
    name: "brain_stats",
    label: "Brain Stats",
    description: "Show third-brain statistics — file counts by type, index status.",
    parameters: Type.Object({}) as any,
    async execute(_id, _params, _signal, _update, _ctx) {
      const result = runScript("sync-index.ts");
      const fileCount = parseFileCount(result.stdout);

      console.error(`[third-brain] Stats: ${fileCount} files`);

      if (result.ok && fileCount > 0) {
        return ok(`🧠 Third-brain stats:\n\n${result.stdout}`);
      } else if (result.ok) {
        return ok("🧠 Brain is empty. Run bootstrap to seed initial knowledge.");
      } else {
        return ok(`⚠️ Stats unavailable: ${result.stderr}`);
      }
    },
  });
}

